/// BTButtonGroup — barrel export.
library;

export 'button_group.types.dart';
export 'button_group.widget.dart';

import 'package:flutter/material.dart';

/// Visual style of a [BTButtonGroup] or individual [BTButtonGroupItemDef].
enum BTButtonGroupVariant {
  /// Light grey background (`bg.secondary`).
  defaultLight,

  /// White background (`bg.primary`). Group gets outer border.
  defaultWhite,

  /// Brand-primary blue background with inverse text.
  primary,

  /// Error-red background with inverse text.
  destructive,

  /// Warning-amber background with primary text.
  warning,
}

/// Size of the [BTButtonGroup].
enum BTButtonGroupSize {
  /// 32 px tall — 8px padding all sides.
  small,

  /// 40 px tall — 12px vertical, 16px horizontal (4px when icon-only).
  large,
}

/// Data definition for a single button inside [BTButtonGroup].
class BTButtonGroupItemDef {
  const BTButtonGroupItemDef({
    this.label,
    this.leftIcon,
    this.rightIcon,
    this.iconOnly = false,
    this.variant,
    this.disabled = false,
    this.onTap,
  });

  /// Label text shown inside the button (unless [iconOnly] is true).
  final String? label;

  /// Optional icon rendered to the left of [label].
  final Widget? leftIcon;

  /// Optional icon rendered to the right of [label] (e.g. chevron-down).
  final Widget? rightIcon;

  /// When true renders only icon(s) with square padding — no label.
  final bool iconOnly;

  /// Per-item variant override. Falls back to the group variant when null.
  final BTButtonGroupVariant? variant;

  /// Disables this item (opacity 0.5, pointer blocked).
  final bool disabled;

  /// Callback fired on tap.
  final VoidCallback? onTap;
}

// BTButtonGroup — horizontal group of action buttons sharing borders.
// Figma: nodes 749-4513, 749-4128.
//
// Usage:
//   BTButtonGroup(items: [
//     BTButtonGroupItemDef(label: 'Copy',  onTap: copy),
//     BTButtonGroupItemDef(label: 'Paste', onTap: paste),
//   ])
//
//   // Mixed variants (Approve / Revise / Reject)
//   BTButtonGroup(items: [
//     BTButtonGroupItemDef(
//       label: 'Approve',
//       variant: BTButtonGroupVariant.primary,
//       onTap: approve,
//     ),
//     BTButtonGroupItemDef(
//       label: 'Revise',
//       variant: BTButtonGroupVariant.warning,
//       onTap: revise,
//     ),
//     BTButtonGroupItemDef(
//       label: 'Reject',
//       variant: BTButtonGroupVariant.destructive,
//       onTap: reject,
//     ),
//   ])

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/button_group/button_group.types.dart';
import 'package:btech_ui/src/components/atoms/button_group/internal/button_group_item.dart';
import 'package:flutter/material.dart';

/// Horizontal group of related action buttons that share borders and appear
/// as one unified control. Supports 5 variants, 2 sizes, and per-item
/// variant mixing.
class BTButtonGroup extends StatelessWidget {
  const BTButtonGroup({
    required this.items,
    this.size = BTButtonGroupSize.large,
    this.variant = BTButtonGroupVariant.defaultLight,
    this.semanticLabel,
    super.key,
  });

  /// Button items to render.
  final List<BTButtonGroupItemDef> items;

  /// Height size — large (40 px) or small (32 px). @default large
  final BTButtonGroupSize size;

  /// Default variant for all items. Per-item
  /// [BTButtonGroupItemDef.variant] overrides this.
  final BTButtonGroupVariant variant;

  /// Semantic label for accessibility (Semantics widget wrapper).
  final String? semanticLabel;

  BTButtonGroupVariant _effectiveVariant(BTButtonGroupItemDef item) =>
      item.variant ?? variant;

  BTButtonGroupItemPosition _position(int index) {
    final total = items.length;
    if (total == 1) return BTButtonGroupItemPosition.only;
    if (index == 0) return BTButtonGroupItemPosition.first;
    if (index == total - 1) return BTButtonGroupItemPosition.last;
    return BTButtonGroupItemPosition.middle;
  }

  bool get _isWhiteGroup => items.every(
        (item) => _effectiveVariant(item) == BTButtonGroupVariant.defaultWhite,
      );

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final radius = context.btRadius;

    final row = IntrinsicHeight(
      child: Row(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          for (var i = 0; i < items.length; i++)
            BTButtonGroupItemWidget(
              key: ValueKey(i),
              item: items[i],
              effectiveVariant: _effectiveVariant(items[i]),
              position: _position(i),
              size: size,
            ),
        ],
      ),
    );

    if (_isWhiteGroup) {
      return Semantics(
        label: semanticLabel,
        child: Container(
          decoration: BoxDecoration(
            border: Border.all(color: colors.border.primary),
            borderRadius: BorderRadius.circular(radius.sm),
          ),
          child: ClipRRect(
            borderRadius: BorderRadius.circular(radius.sm),
            child: row,
          ),
        ),
      );
    }

    return Semantics(
      label: semanticLabel,
      child: ClipRRect(
        borderRadius: BorderRadius.circular(radius.sm),
        child: row,
      ),
    );
  }
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/button_group/button_group.types.dart';
import 'package:flutter/material.dart';

/// Position of an item within the group — controls which corners are rounded.
enum BTButtonGroupItemPosition { only, first, middle, last }

/// Private stateful item widget that owns hover / press state.
/// CLAUDE.md §12 — uses plain Container + setState, NO AnimatedContainer.
class BTButtonGroupItemWidget extends StatefulWidget {
  const BTButtonGroupItemWidget({
    required this.item,
    required this.effectiveVariant,
    required this.position,
    required this.size,
    super.key,
  });

  final BTButtonGroupItemDef item;
  final BTButtonGroupVariant effectiveVariant;
  final BTButtonGroupItemPosition position;
  final BTButtonGroupSize size;

  @override
  State<BTButtonGroupItemWidget> createState() =>
      _BTButtonGroupItemWidgetState();
}

class _BTButtonGroupItemWidgetState extends State<BTButtonGroupItemWidget> {
  bool _hovered = false;
  bool _pressed = false;

  Color _bgColor(BTColorTheme colors) {
    if (widget.item.disabled) {
      return _baseBg(colors);
    }
    switch (widget.effectiveVariant) {
      case BTButtonGroupVariant.defaultLight:
        if (_pressed) return colors.bg.subtlest;
        if (_hovered) return colors.bg.subtler;
        return colors.bg.secondary;
      case BTButtonGroupVariant.defaultWhite:
        if (_pressed) return colors.bg.subtler;
        if (_hovered) return colors.bg.secondary;
        return colors.bg.primary;
      case BTButtonGroupVariant.primary:
        if (_pressed || _hovered) return BTColor.brand.primaryBold;
        return BTColor.brand.primary;
      case BTButtonGroupVariant.destructive:
        if (_pressed || _hovered) return BTColor.ext.errorBold;
        return BTColor.ext.error;
      case BTButtonGroupVariant.warning:
        if (_pressed || _hovered) return BTColor.ext.warningBold;
        return BTColor.ext.warning;
    }
  }

  Color _baseBg(BTColorTheme colors) {
    switch (widget.effectiveVariant) {
      case BTButtonGroupVariant.defaultLight:
        return colors.bg.secondary;
      case BTButtonGroupVariant.defaultWhite:
        return colors.bg.primary;
      case BTButtonGroupVariant.primary:
        return BTColor.brand.primary;
      case BTButtonGroupVariant.destructive:
        return BTColor.ext.error;
      case BTButtonGroupVariant.warning:
        return BTColor.ext.warning;
    }
  }

  Color _fgColor(BTColorTheme colors) {
    switch (widget.effectiveVariant) {
      case BTButtonGroupVariant.primary:
      case BTButtonGroupVariant.destructive:
        return colors.text.inverse;
      case BTButtonGroupVariant.defaultLight:
      case BTButtonGroupVariant.defaultWhite:
      case BTButtonGroupVariant.warning:
        return colors.text.primary;
    }
  }

  BorderRadiusGeometry _borderRadius(double sm) {
    switch (widget.position) {
      case BTButtonGroupItemPosition.only:
        return BorderRadius.circular(sm);
      case BTButtonGroupItemPosition.first:
        return BorderRadiusDirectional.only(
          topStart: Radius.circular(sm),
          bottomStart: Radius.circular(sm),
        );
      case BTButtonGroupItemPosition.last:
        return BorderRadiusDirectional.only(
          topEnd: Radius.circular(sm),
          bottomEnd: Radius.circular(sm),
        );
      case BTButtonGroupItemPosition.middle:
        return BorderRadius.zero;
    }
  }

  EdgeInsets _padding() {
    if (widget.size == BTButtonGroupSize.small) {
      return EdgeInsets.all(8.0);
    }
    // large
    if (widget.item.iconOnly) return EdgeInsets.all(12.0);
    return EdgeInsets.symmetric(horizontal: 16.0, vertical: 12.0);
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final radius = context.btRadius;
    final isFirst = widget.position == BTButtonGroupItemPosition.first ||
        widget.position == BTButtonGroupItemPosition.only;

    final content = Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        if (widget.item.leftIcon != null) ...[
          SizedBox(
            width: 16.0,
            height: 16.0,
            child: FittedBox(child: widget.item.leftIcon),
          ),
          if (!widget.item.iconOnly && widget.item.label != null)
            SizedBox(width: 4.0),
        ],
        if (!widget.item.iconOnly && widget.item.label != null)
          Text(
            widget.item.label!,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w500,
              height: 16 / 12,
              color: _fgColor(colors),
            ),
          ),
        if (widget.item.rightIcon != null) ...[
          if (!widget.item.iconOnly && widget.item.label != null)
            SizedBox(width: 4.0),
          SizedBox(
            width: 16.0,
            height: 16.0,
            child: FittedBox(child: widget.item.rightIcon),
          ),
        ],
      ],
    );

    return Opacity(
      opacity: widget.item.disabled ? 0.5 : 1.0,
      child: MouseRegion(
        cursor: widget.item.disabled
            ? SystemMouseCursors.forbidden
            : SystemMouseCursors.click,
        onEnter: widget.item.disabled
            ? null
            : (_) => setState(() => _hovered = true),
        onExit: widget.item.disabled
            ? null
            : (_) => setState(() => _hovered = false),
        child: GestureDetector(
          onTap: widget.item.disabled ? null : widget.item.onTap,
          onTapDown: widget.item.disabled
              ? null
              : (_) => setState(() => _pressed = true),
          onTapUp: widget.item.disabled
              ? null
              : (_) => setState(() => _pressed = false),
          onTapCancel: widget.item.disabled
              ? null
              : () => setState(() => _pressed = false),
          child: Container(
            padding: _padding(),
            decoration: BoxDecoration(
              color: _bgColor(colors),
              borderRadius: _borderRadius(radius.sm),
              border: isFirst
                  ? null
                  : BorderDirectional(
                      start: BorderSide(
                        color: colors.border.tertiary,
                      ),
                    ),
            ),
            child: content,
          ),
        ),
      ),
    );
  }
}
